mapper.select:
SELECT

FROM ai_custom_query_scheme
WHERE tenant_id = #{tenantId}
  AND create_by = #{userId}
  AND config_key = #{configKey}
ORDER BY is_default DESC, update_time DESC, id DESC

SELECT

FROM ai_custom_query_scheme
WHERE tenant_id = #{tenantId}
  AND create_by = #{userId}
  AND config_key = #{configKey}
  AND id = #{id}
LIMIT 1

mapper.update:
UPDATE ai_custom_query_scheme
SET is_default = 0,
    update_by = #{userId},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND create_by = #{userId}
  AND config_key = #{configKey}
  AND is_default = 1

mapper.delete:
DELETE FROM ai_custom_query_scheme
WHERE tenant_id = #{tenantId}
  AND create_by = #{userId}
  AND config_key = #{configKey}
  AND id = #{id}
